import {
  geo,
  geoFromHeaders,
  isInRegion,
  geoDistance,
  COUNTRY_NAMES,
} from './geo'
import type { Geo } from './geo'

function makeHeaders(init: Record<string, string>): Headers {
  return new Headers(init)
}

describe('geoFromHeaders', () => {
  it('should extract all geo fields from Vercel headers', () => {
    const headers = makeHeaders({
      'x-vercel-ip-city': 'New York',
      'x-vercel-ip-country': 'US',
      'x-vercel-ip-country-region': 'NY',
      'x-vercel-ip-latitude': '40.7128',
      'x-vercel-ip-longitude': '-74.0060',
      'x-vercel-ip-timezone': 'America/New_York',
    })

    const result = geoFromHeaders(headers)
    expect(result.city).toBe('New York')
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
    expect(result.region).toBe('NY')
    expect(result.latitude).toBe('40.7128')
    expect(result.longitude).toBe('-74.0060')
    expect(result.timezone).toBe('America/New_York')
  })

  it('should return undefined for missing headers', () => {
    const headers = makeHeaders({})
    const result = geoFromHeaders(headers)

    expect(result.city).toBeUndefined()
    expect(result.country).toBeUndefined()
    expect(result.countryCode).toBeUndefined()
    expect(result.region).toBeUndefined()
    expect(result.latitude).toBeUndefined()
    expect(result.longitude).toBeUndefined()
    expect(result.timezone).toBeUndefined()
  })

  it('should fall back to cf-ipcountry when x-vercel-ip-country is absent', () => {
    const headers = makeHeaders({
      'cf-ipcountry': 'DE',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('DE')
    expect(result.country).toBe('Germany')
  })

  it('should prefer x-vercel-ip-country over cf-ipcountry', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'US',
      'cf-ipcountry': 'DE',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('US')
    expect(result.country).toBe('United States')
  })

  it('should derive country name from countryCode via COUNTRY_NAMES', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'JP',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('JP')
    expect(result.country).toBe('Japan')
  })

  it('should return undefined country for unknown countryCode', () => {
    const headers = makeHeaders({
      'x-vercel-ip-country': 'ZZ',
    })

    const result = geoFromHeaders(headers)
    expect(result.countryCode).toBe('ZZ')
    expect(result.country).toBeUndefined()
  })

  it('should decode URL-encoded city names', () => {
    const headers = makeHeaders({
      'x-vercel-ip-city': 'S%C3%A3o%20Paulo',
    })

    const result = geoFromHeaders(headers)
    expect(result.city).toBe('São Paulo')
  })

  it('should handle malformed URL-encoded city names gracefully', () => {
    const headers = makeHeaders({
      'x-vercel-ip-city': '%E0%A4%A',
    })

    const result = geoFromHeaders(headers)
    // Falls back to the raw header value on decode failure
    expect(result.city).toBe('%E0%A4%A')
  })
})

describe('geo', () => {
  it('should extract geo from a request-like object with headers', () => {
    const headers = makeHeaders({
      'x-vercel-ip-city': 'London',
      'x-vercel-ip-country': 'GB',
      'x-vercel-ip-country-region': 'ENG',
      'x-vercel-ip-latitude': '51.5074',
      'x-vercel-ip-longitude': '-0.1278',
      'x-vercel-ip-timezone': 'Europe/London',
    })

    const result = geo({ headers })
    expect(result.city).toBe('London')
    expect(result.countryCode).toBe('GB')
    expect(result.country).toBe('United Kingdom')
    expect(result.region).toBe('ENG')
    expect(result.latitude).toBe('51.5074')
    expect(result.longitude).toBe('-0.1278')
    expect(result.timezone).toBe('Europe/London')
  })
})

describe('isInRegion', () => {
  it('should return true when countryCode matches a region', () => {
    const geoData: Geo = { countryCode: 'US' }
    expect(isInRegion(geoData, ['US', 'CA', 'GB'])).toBe(true)
  })

  it('should perform case-insensitive comparison', () => {
    const geoData: Geo = { countryCode: 'us' }
    expect(isInRegion(geoData, ['US', 'CA'])).toBe(true)

    const geoData2: Geo = { countryCode: 'US' }
    expect(isInRegion(geoData2, ['us', 'ca'])).toBe(true)
  })

  it('should return false when countryCode does not match', () => {
    const geoData: Geo = { countryCode: 'DE' }
    expect(isInRegion(geoData, ['US', 'CA', 'GB'])).toBe(false)
  })

  it('should return false when countryCode is undefined', () => {
    const geoData: Geo = {}
    expect(isInRegion(geoData, ['US', 'CA'])).toBe(false)
  })
})

describe('geoDistance', () => {
  it('should calculate New York to London distance within 50km tolerance', () => {
    // New York: 40.7128, -74.0060
    // London: 51.5074, -0.1278
    const distance = geoDistance('40.7128', '-74.0060', '51.5074', '-0.1278')
    expect(Math.abs(distance - 5570)).toBeLessThan(50)
  })

  it('should return 0 for identical points', () => {
    const distance = geoDistance('40.7128', '-74.0060', '40.7128', '-74.0060')
    expect(distance).toBe(0)
  })

  it('should return NaN for non-numeric inputs', () => {
    expect(geoDistance('abc', '0', '0', '0')).toBeNaN()
    expect(geoDistance('0', 'xyz', '0', '0')).toBeNaN()
    expect(geoDistance('0', '0', 'abc', '0')).toBeNaN()
    expect(geoDistance('0', '0', '0', 'xyz')).toBeNaN()
  })

  it('should handle antipodal points', () => {
    // North pole to south pole ~ 20015 km
    const distance = geoDistance('90', '0', '-90', '0')
    expect(Math.abs(distance - 20015)).toBeLessThan(20)
  })
})

describe('COUNTRY_NAMES', () => {
  it('should contain at least 10 country codes', () => {
    expect(Object.keys(COUNTRY_NAMES).length).toBeGreaterThanOrEqual(10)
  })

  it('should map US to United States', () => {
    expect(COUNTRY_NAMES['US']).toBe('United States')
  })

  it('should map GB to United Kingdom', () => {
    expect(COUNTRY_NAMES['GB']).toBe('United Kingdom')
  })

  it('should contain all required country codes', () => {
    const requiredCodes = [
      'US',
      'GB',
      'DE',
      'FR',
      'JP',
      'CN',
      'IN',
      'BR',
      'AU',
      'CA',
    ]
    for (const code of requiredCodes) {
      expect(COUNTRY_NAMES).toHaveProperty(code)
    }
  })
})
